from itertools import combinations

def find_most_frequent_pair(df):
    pair_counts = {}
    grouped = df.groupby('transaction_id')['product'].apply(list)
    for products in grouped:
        # get all unique pairs sorted alphabetically in this transaction
        pairs = combinations(sorted(set(products)), 2)
        for pair in pairs:
            pair_counts[pair] = pair_counts.get(pair, 0) + 1
    # find pair with max count
    most_frequent_pair = max(pair_counts, key=pair_counts.get)
    return list(most_frequent_pair)

