def customers_with_purchases_every_quarter(df):
    df['purchase_date'] = pd.to_datetime(df['purchase_date'])
    df['quarter'] = df['purchase_date'].dt.quarter
    # Group by customer and collect quarters
    quarters_per_customer = df.groupby('customer_id')['quarter'].apply(set)
    # Filter customers with all quarters {1,2,3,4}
    all_quarters = {1, 2, 3, 4}
    customers = quarters_per_customer[quarters_per_customer.apply(lambda x: x == all_quarters)].index
    return sorted(customers.tolist())

