import pandas as pd

def count_users_with_30_day_streak(df):
    df['login_date'] = pd.to_datetime(df['login_date'])
    result = 0
    for user, group in df.groupby('user_id'):
        dates = group['login_date'].drop_duplicates().sort_values()
        if len(dates) < 30:
            continue
        # Compute difference between consecutive dates
        diffs = dates.diff().dt.days.fillna(1)
        streak = 1
        max_streak = 1
        for diff in diffs.iloc[1:]:
            if diff == 1:
                streak += 1
                max_streak = max(max_streak, streak)
            else:
                streak = 1
        if max_streak >= 30:
            result += 1
    return result

