from itertools import combinations

def find_pairs(df):
    # Group by student and aggregate courses as sorted tuple
    student_courses = df.groupby('student_id')['course_id'].apply(lambda x: tuple(sorted(x.unique()))).reset_index()

    # Create a mapping from course sets to list of students
    course_to_students = {}
    for _, row in student_courses.iterrows():
        course_set = row['course_id']
        course_to_students.setdefault(course_set, []).append(row['student_id'])

    pairs = []
    # For each group with more than one student, list all unique pairs
    for students in course_to_students.values():
        if len(students) > 1:
            for pair in combinations(sorted(students), 2):
                pairs.append(list(pair))
    return pairs

