from scipy.stats import linregress

def determine_trend(df):
    trend_dict = {}
    for product, group in df.groupby('product_id'):
        slope, intercept, r_value, p_value, std_err = linregress(group['month'], group['sales'])
        # Use p < 0.05 for significance and slope sign for trend
        if p_value < 0.05:
            if slope > 0:
                trend = 'up'
            elif slope < 0:
                trend = 'down'
            else:
                trend = 'flat'
        else:
            trend = 'flat'
        trend_dict[product] = trend
    return trend_dict

